/**
 * Apotheca Marketing Suite — Email Templates Manager
 * List, create, edit, delete saved email templates.
 * Reuses the same editor patterns from ams-email-editor.min.js.
 */
(function ($) {
    'use strict';

    var el = wp.element.createElement;
    var useState = wp.element.useState;
    var useEffect = wp.element.useEffect;
    var Button = wp.components.Button;
    var TextControl = wp.components.TextControl;
    var Notice = wp.components.Notice;
    var Spinner = wp.components.Spinner;
    var apiFetch = wp.apiFetch;
    var cfg = window.amsEmailTemplates || {};

    var FONT_STACK = "'Montserrat','Century Gothic','Trebuchet MS',Arial,Helvetica,sans-serif";

    /* ── Block type definitions (same as email editor) ── */
    var BLOCK_DEFS = {
        text:       { label: 'Text', icon: 'dashicons-editor-textcolor', defaults: { content: '<p>Enter your text here...</p>', align: 'left', padding: '10px 20px' } },
        'hero-image': { label: 'Hero Image', icon: 'dashicons-cover-image', defaults: { src: '', alt: '', link: '', overlayText: '', overlaySubtext: '', buttonText: '', buttonUrl: '#', buttonColor: '#ffffff', buttonBg: '#2271b1', overlayColor: 'rgba(0,0,0,0.4)', textColor: '#ffffff', height: '300px', align: 'center' } },
        image:      { label: 'Image', icon: 'dashicons-format-image', defaults: { src: '', alt: '', width: '100%', align: 'center', link: '', padding: '10px 20px' } },
        button:     { label: 'Button', icon: 'dashicons-button', defaults: { text: 'Click Here', url: '#', bgColor: '#2271b1', textColor: '#ffffff', borderRadius: '4px', align: 'center', padding: '12px 24px', containerPadding: '10px 20px' } },
        divider:    { label: 'Divider', icon: 'dashicons-minus', defaults: { color: '#cccccc', thickness: '1px', style: 'solid', padding: '10px 20px' } },
        spacer:     { label: 'Spacer', icon: 'dashicons-image-flip-vertical', defaults: { height: '20px' } },
        'product-card': { label: 'Product Card', icon: 'dashicons-cart', defaults: { productName: '{{product_name}}', productUrl: '{{product_url}}', imageUrl: '{{product_image_url}}', price: '{{product_price}}', buttonText: 'Shop Now', buttonColor: '#2271b1', padding: '10px 20px' } },
        reviews:    { label: 'Reviews', icon: 'dashicons-star-filled', defaults: { mode: 'review_request', heading: 'How was your purchase?', buttonText: 'Leave a Review', buttonColor: '#2271b1', reviewCount: 3, selectionMode: 'auto_contextual', productId: '', minRating: 4, showStars: true, showReviewerName: true, showVerifiedBadge: true, showProductName: false, showDate: false, truncateLength: 120, starColor: '#f5a623', cardBg: '#ffffff', padding: '10px 20px' } },
        'social-links': { label: 'Social Links', icon: 'dashicons-share', defaults: { facebook: '#', instagram: '#', twitter: '#', youtube: '', align: 'center', padding: '10px 20px' } },
        'unsubscribe-footer': { label: 'Unsub Footer', icon: 'dashicons-dismiss', defaults: { text: 'You received this email because you opted in at {{shop_name}}.', linkText: 'Unsubscribe', align: 'center', padding: '20px' } },
        'blank-row': { label: 'Blank Row', icon: 'dashicons-minus', defaults: { width: '100%', height: '40px', bgColor: '#f7f7f7' } },
        /* Flow / Dynamic Content */
        'greeting': { label: 'Greeting', icon: 'dashicons-admin-users', defaults: { greeting: 'Hi', fallback: 'there', field: 'first_name', align: 'left', fontSize: '16px', padding: '10px 20px' } },
        'order-summary': { label: 'Order Summary', icon: 'dashicons-clipboard', defaults: { showOrderNumber: true, showOrderDate: true, showOrderTotal: true, showOrderStatus: true, padding: '10px 20px' } },
        'cart-items': { label: 'Cart Items', icon: 'dashicons-products', defaults: { heading: 'Items in Your Cart', buttonText: 'Complete Order', buttonUrl: '{{cart_url}}', buttonColor: '#2271b1', showImage: true, showPrice: true, padding: '10px 20px' } },
        'coupon': { label: 'Coupon Code', icon: 'dashicons-tag', defaults: { heading: 'Your Exclusive Discount', codeVar: '{{coupon_code}}', bgColor: '#f0f9ff', borderColor: '#2271b1', textColor: '#333', fontSize: '22px', padding: '10px 20px' } },
        'ai-recommendations': { label: 'AI Recs', icon: 'dashicons-lightbulb', defaults: { heading: 'Recommended For You', padding: '10px 20px' } },
        'token-block': { label: 'Dynamic Text', icon: 'dashicons-editor-code', defaults: { token: 'first_name', before: '', after: '', align: 'left', fontSize: '16px', padding: '10px 20px' } },
        'product-showcase': { label: 'Products', icon: 'dashicons-products', defaults: { productIds: '', buttonText: 'SHOP NOW', buttonBg: '#000000', buttonTextColor: '#ffffff', cardBg: '#f5f5f5', showDescription: true, padding: '10px 0' } }
    };

    /* ── Template Editor (jQuery-based, same pattern as campaign editor) ── */
    var Editor = {
        el: null,
        templateId: 0,
        templateName: 'Untitled Template',
        structure: null,
        selectedRow: null,
        _dragging: false,

        init: function (node) {
            this.el = $(node);
            this.templateId = parseInt(this.el.data('template-id')) || 0;
            this.structure = { settings: { bgColor: '#f4f4f4', contentBg: '#ffffff', fontWeight: '400', fontSize: '16px', textColor: '#333333', linkColor: '#2271b1', maxWidth: '600', preheader: '' }, rows: [] };
            if (this.templateId) {
                this.load();
            } else {
                this.render();
                this.bindEvents();
            }
        },

        load: function () {
            var self = this;
            this.el.html('<div style="padding:40px;text-align:center;">Loading...</div>');
            apiFetch({
                path: '/ams/v1/admin/email-templates/' + this.templateId,
                headers: { 'X-WP-Nonce': cfg.nonce },
            }).then(function (t) {
                self.templateName = t.name || 'Untitled Template';
                if (t.structure_json) {
                    try {
                        var parsed = JSON.parse(t.structure_json);
                        if (parsed.rows) self.structure.rows = parsed.rows;
                        if (parsed.settings) self.structure.settings = $.extend({}, self.structure.settings, parsed.settings);
                    } catch (e) { /* ignore */ }
                }
                self.render();
                self.bindEvents();
            }).catch(function () {
                self.render();
                self.bindEvents();
            });
        },

        render: function () {
            var s = this.structure.settings;
            var html = '';

            /* Top toolbar — full width across both sidebar and canvas */
            html += '<div class="ams-etb-toolbar">';
            html += '<input type="text" class="ams-tpl-name-input" value="' + this.esc(this.templateName) + '" placeholder="Template name" style="flex:1;font-size:14px;font-weight:600;" />';
            html += '<button class="button ams-etb-preview-btn">Preview</button>';
            html += '<button class="button button-primary ams-etb-save-btn">Save Template</button>';
            html += '</div>';

            /* Main body — sidebar + canvas side by side */
            html += '<div class="ams-etb-main">';

            /* Sidebar */
            html += '<div class="ams-etb-sidebar">';
            html += '<div class="ams-etb-tabs">';
            html += '<button class="ams-etb-tab active" data-panel="blocks">Blocks</button>';
            html += '<button class="ams-etb-tab" data-panel="settings">Design</button>';
            html += '<button class="ams-etb-tab" data-panel="block-settings">Block</button>';
            html += '</div>';

            html += '<div class="ams-etb-panel active" data-panel="blocks">';
            html += '<div class="ams-etb-block-grid">';
            for (var type in BLOCK_DEFS) {
                var bd = BLOCK_DEFS[type];
                html += '<div class="ams-etb-block-item" data-type="' + type + '" draggable="true">';
                html += '<span class="dashicons ' + bd.icon + '"></span>';
                html += '<span>' + bd.label + '</span></div>';
            }
            html += '</div></div>';

            html += '<div class="ams-etb-panel" data-panel="settings">';
            html += this.renderDesignSettings();
            html += '</div>';

            html += '<div class="ams-etb-panel" data-panel="block-settings">';
            html += '<p style="color:#999;text-align:center;padding:20px;">Select a block to edit.</p>';
            html += '</div>';
            html += '</div>'; /* end sidebar */

            /* Canvas */
            html += '<div class="ams-etb-canvas">';
            html += '<div class="ams-etb-email-frame" style="max-width:' + (parseInt(s.maxWidth) || 600) + 'px;">';
            html += '<div class="ams-etb-email-body" style="background:' + (s.contentBg || '#fff') + ';">';
            html += this.renderRows();
            html += '</div></div>';
            html += '</div>'; /* end canvas */

            html += '</div>'; /* end main */

            this.el.html(html);
            this.initSortable();
        },

        renderRows: function () {
            if (!this.structure.rows || !this.structure.rows.length) {
                return '<div class="ams-etb-drop-zone">Drag blocks here to start building your template</div>';
            }
            var html = '<div class="ams-etb-drop-zone has-blocks">';
            for (var i = 0; i < this.structure.rows.length; i++) {
                html += this.renderRow(i, this.structure.rows[i]);
            }
            html += '</div>';
            return html;
        },

        renderRow: function (index, row) {
            var blocks = row.blocks || [];
            var rowStyle = '';
            if (blocks.length === 1 && blocks[0].type === 'blank-row') {
                rowStyle = ' style="background:' + (blocks[0].props.bgColor || '#f7f7f7') + ';"';
            }
            var html = '<div class="ams-etb-row" data-index="' + index + '"' + rowStyle + '>';
            html += '<div class="ams-etb-row-actions">';
            html += '<button class="ams-etb-row-action move" title="Drag to reorder"><span class="dashicons dashicons-move"></span></button>';
            html += '<button class="ams-etb-row-action duplicate" title="Duplicate"><span class="dashicons dashicons-admin-page"></span></button>';
            html += '<button class="ams-etb-row-action delete" title="Delete"><span class="dashicons dashicons-trash"></span></button>';
            html += '</div>';
            for (var j = 0; j < blocks.length; j++) {
                html += '<div class="ams-etb-block" data-row="' + index + '" data-block="' + j + '" data-type="' + blocks[j].type + '">';
                html += this.renderBlockPreview(blocks[j]);
                html += '</div>';
            }
            html += '</div>';
            return html;
        },

        renderBlockPreview: function (block) {
            var p = block.props || {};
            var pad = p.padding || '10px 20px';
            switch (block.type) {
                case 'text': return '<div style="padding:' + pad + ';text-align:' + (p.align || 'left') + ';">' + (p.content || '<p>Text</p>') + '</div>';
                case 'hero-image':
                    if (p.src) {
                        var hh = '<div style="background:#111 url(' + this.esc(p.src) + ') center/cover no-repeat;min-height:' + (p.height || '300px') + ';display:flex;align-items:center;justify-content:center;text-align:center;"><div style="padding:30px 20px;color:' + (p.textColor || '#fff') + ';">';
                        if (p.overlayText) hh += '<h2 style="margin:0 0 8px;font-size:28px;font-weight:700;">' + p.overlayText + '</h2>';
                        if (p.overlaySubtext) hh += '<p style="margin:0 0 16px;font-size:16px;">' + p.overlaySubtext + '</p>';
                        if (p.buttonText) hh += '<span style="display:inline-block;background:' + (p.buttonBg || '#2271b1') + ';color:' + (p.buttonColor || '#fff') + ';padding:12px 28px;border-radius:4px;font-weight:600;">' + this.esc(p.buttonText) + '</span>';
                        hh += '</div></div>';
                        return hh;
                    }
                    return '<div style="min-height:180px;background:linear-gradient(135deg,#667eea 0%,#764ba2 100%);display:flex;align-items:center;justify-content:center;color:#fff;text-align:center;padding:30px;"><div><span class="dashicons dashicons-cover-image" style="font-size:36px;width:36px;height:36px;opacity:0.7;"></span><p style="margin:8px 0 0;font-size:13px;opacity:0.9;">Hero Image</p></div></div>';
                case 'image':
                    if (p.src) return '<div style="padding:' + pad + ';text-align:' + (p.align || 'center') + ';"><img src="' + this.esc(p.src) + '" style="max-width:' + (p.width || '100%') + ';height:auto;" /></div>';
                    return '<div style="padding:20px;text-align:center;background:#f0f0f1;border:1px dashed #c3c4c7;margin:10px 20px;border-radius:4px;"><span class="dashicons dashicons-format-image" style="font-size:32px;color:#ccc;"></span><br><small style="color:#999;">Image</small></div>';
                case 'button': return '<div style="padding:' + (p.containerPadding || '10px 20px') + ';text-align:' + (p.align || 'center') + ';"><span style="display:inline-block;background:' + (p.bgColor || '#2271b1') + ';color:' + (p.textColor || '#fff') + ';padding:' + (p.padding || '12px 24px') + ';border-radius:' + (p.borderRadius || '4px') + ';font-weight:600;">' + this.esc(p.text || 'Button') + '</span></div>';
                case 'divider': return '<div style="padding:' + pad + ';"><hr style="border:none;border-top:' + (p.thickness || '1px') + ' ' + (p.style || 'solid') + ' ' + (p.color || '#ccc') + ';margin:0;" /></div>';
                case 'spacer': return '<div style="height:' + (p.height || '20px') + ';background:repeating-linear-gradient(45deg,transparent,transparent 5px,#f8f8f8 5px,#f8f8f8 10px);"></div>';
                case 'blank-row': return '<div style="width:' + (p.width || '100%') + ';height:' + (p.height || '40px') + ';background:' + (p.bgColor || '#f7f7f7') + ';"></div>';
                case 'product-card': return '<div style="padding:' + pad + ';text-align:center;border:1px dashed #ddd;border-radius:4px;"><span class="dashicons dashicons-cart" style="font-size:24px;color:#ccc;"></span><br><small style="color:#999;">Product Card</small></div>';
                case 'reviews':
                    var rvh = '<div style="padding:' + pad + ';text-align:center;"><h3 style="margin:0 0 8px;">' + (p.heading || 'Reviews') + '</h3>';
                    if (p.mode === 'social_proof') {
                        var rc = Math.min(parseInt(p.reviewCount) || 3, 3);
                        rvh += '<p style="font-size:11px;color:#999;margin:0 0 8px;">' + rc + ' reviews \u00b7 ' + (p.minRating || 4) + '+ stars</p>';
                        for (var rri = 0; rri < rc; rri++) {
                            rvh += '<div style="background:' + (p.cardBg || '#fff') + ';border:1px solid #e0e0e0;border-radius:6px;padding:10px;text-align:left;margin-bottom:6px;">';
                            if (p.showStars !== false) rvh += '<div style="color:' + (p.starColor || '#f5a623') + ';font-size:14px;">\u2605\u2605\u2605\u2605\u2605</div>';
                            rvh += '<p style="margin:2px 0;font-size:12px;font-style:italic;color:#555;">"Great product!"</p>';
                            if (p.showReviewerName !== false) rvh += '<span style="font-size:11px;color:#666;">Jane D.' + (p.showVerifiedBadge !== false ? ' <span style="color:#00a32a;">\u2713</span>' : '') + '</span>';
                            rvh += '</div>';
                        }
                    } else if (p.mode === 'review_gate') {
                        rvh += '<div style="font-size:28px;letter-spacing:6px;color:' + (p.starColor || '#f5a623') + ';">\u2605\u2605\u2605\u2605\u2605</div>';
                    } else {
                        rvh += '<div style="font-size:24px;color:' + (p.starColor || '#f5a623') + ';">\u2605\u2605\u2605\u2605\u2605</div>';
                        rvh += '<span style="display:inline-block;background:' + (p.buttonColor || '#2271b1') + ';color:#fff;padding:10px 20px;border-radius:4px;font-weight:600;font-size:13px;margin-top:8px;">' + this.esc(p.buttonText || 'Leave a Review') + '</span>';
                    }
                    rvh += '</div>';
                    return rvh;
                case 'social-links': return '<div style="text-align:center;padding:' + pad + ';"><span style="display:inline-block;margin:0 4px;padding:6px 10px;background:#e0e0e0;border-radius:4px;font-size:11px;">Facebook</span><span style="display:inline-block;margin:0 4px;padding:6px 10px;background:#e0e0e0;border-radius:4px;font-size:11px;">Instagram</span></div>';
                case 'unsubscribe-footer': return '<div style="text-align:center;padding:' + (p.padding || '20px') + ';font-size:12px;color:#999;"><p style="margin:0 0 8px;">' + (p.text || 'Footer') + '</p><a href="#" style="color:#2271b1;">Unsubscribe</a></div>';
                case 'greeting': return '<div style="padding:' + pad + ';text-align:' + (p.align || 'left') + ';font-size:' + (p.fontSize || '16px') + ';">' + this.esc(p.greeting || 'Hi') + ' <span style="color:#2271b1;font-weight:600;">{{' + (p.field || 'first_name') + '}}</span><span style="color:#999;font-size:12px;"> (fallback: "' + this.esc(p.fallback || 'there') + '")</span></div>';
                case 'order-summary':
                    var os = '<div style="padding:' + pad + ';"><table style="width:100%;font-size:14px;">';
                    os += '<tr><td style="padding:6px 0;border-bottom:1px solid #eee;"><strong>Order</strong></td><td style="text-align:right;padding:6px 0;border-bottom:1px solid #eee;">{{order_number}}</td></tr>';
                    os += '<tr><td style="padding:6px 0;"><strong>Total</strong></td><td style="text-align:right;padding:6px 0;font-weight:700;">{{order_total}}</td></tr>';
                    os += '</table></div>'; return os;
                case 'cart-items': return '<div style="padding:' + pad + ';"><h3 style="margin:0 0 8px;">' + this.esc(p.heading || 'Cart Items') + '</h3><div style="border:1px dashed #c3c4c7;border-radius:6px;padding:16px;text-align:center;background:#f9f9f9;"><span class="dashicons dashicons-products" style="font-size:28px;color:#999;"></span><p style="margin:8px 0 0;color:#666;font-size:12px;">Dynamic cart items at send time</p></div></div>';
                case 'coupon': return '<div style="padding:' + pad + ';"><div style="border:2px dashed ' + (p.borderColor || '#2271b1') + ';background:' + (p.bgColor || '#f0f9ff') + ';border-radius:8px;padding:20px;text-align:center;">' + (p.heading ? '<p style="margin:0 0 8px;font-size:13px;color:#999;text-transform:uppercase;">' + this.esc(p.heading) + '</p>' : '') + '<p style="margin:0;font-size:' + (p.fontSize || '22px') + ';font-weight:700;font-family:monospace;">' + (p.codeVar || '{{coupon_code}}') + '</p></div></div>';
                case 'ai-recommendations': return '<div style="padding:' + pad + ';"><h3 style="margin:0 0 8px;">' + this.esc(p.heading || 'Recommended For You') + '</h3><div style="border:1px dashed #c3c4c7;border-radius:6px;padding:16px;text-align:center;background:#f5f0ff;"><span class="dashicons dashicons-lightbulb" style="font-size:28px;color:#9b59b6;"></span><p style="margin:8px 0 0;color:#666;font-size:12px;">AI recommendations at send time</p></div></div>';
                case 'token-block': return '<div style="padding:' + pad + ';text-align:' + (p.align || 'left') + ';font-size:' + (p.fontSize || '16px') + ';">' + (p.before || '') + '<span style="color:#2271b1;font-weight:600;background:#f0f6fc;padding:2px 6px;border-radius:3px;">{{' + (p.token || 'first_name') + '}}</span>' + (p.after || '') + '</div>';
                case 'product-showcase':
                    var psIds = (p.productIds || '').replace(/\s/g, '');
                    var psArr = psIds ? psIds.split(',') : [];
                    if (!psArr.length) {
                        return '<div style="padding:30px 20px;background:' + (p.cardBg || '#f5f5f5') + ';border:2px dashed #ccc;border-radius:8px;text-align:center;color:#999;">' +
                            '<span class="dashicons dashicons-products" style="font-size:32px;width:32px;height:32px;display:block;margin:0 auto 8px;"></span>' +
                            '<p style="margin:0;font-weight:600;">Product Showcase</p>' +
                            '<p style="margin:4px 0 0;font-size:12px;">Product IDs are set per campaign in the Content tab.</p>' +
                            '</div>';
                    }
                    var psHtml2 = '';
                    for (var psi = 0; psi < psArr.length; psi++) {
                        psHtml2 += '<div style="background:' + (p.cardBg || '#f5f5f5') + ';border-radius:8px;margin-bottom:12px;overflow:hidden;">' +
                            '<table cellpadding="0" cellspacing="0" border="0" width="100%"><tr>' +
                            '<td style="width:45%;padding:20px;background:#e8e8e8;text-align:center;vertical-align:middle;">' +
                            '<span style="color:#999;font-size:13px;">Product #' + this.esc(psArr[psi]) + '</span>' +
                            '</td>' +
                            '<td style="width:55%;padding:24px 28px;vertical-align:top;">' +
                            '<h3 style="margin:0 0 10px;font-size:20px;font-weight:400;">Product #' + this.esc(psArr[psi]) + '</h3>' +
                            (p.showDescription !== false ? '<p style="margin:0 0 14px;color:#888;font-size:14px;line-height:1.5;">Description at send time</p>' : '') +
                            '<p style="margin:0 0 16px;font-size:18px;font-weight:700;">$0.00</p>' +
                            '<span style="display:inline-block;background:' + (p.buttonBg || '#000') + ';color:' + (p.buttonTextColor || '#fff') + ';font-size:13px;font-weight:700;padding:14px 32px;letter-spacing:1px;text-transform:uppercase;">' + this.esc(p.buttonText || 'SHOP NOW') + '</span>' +
                            '</td></tr></table></div>';
                    }
                    return '<div style="padding:' + pad + ';">' + psHtml2 + '</div>';
                default: return '<div style="padding:10px;color:#999;">Block: ' + block.type + '</div>';
            }
        },

        renderDesignSettings: function () {
            var s = this.structure.settings;
            var html = '<div class="ams-etb-settings-group"><h4>Colors</h4>';
            html += this.field('text', 'bgColor', 'Background', s.bgColor || '#f4f4f4');
            html += this.field('text', 'contentBg', 'Content BG', s.contentBg || '#ffffff');
            html += this.field('text', 'textColor', 'Text', s.textColor || '#333333');
            html += this.field('text', 'linkColor', 'Links', s.linkColor || '#2271b1');
            html += '</div><div class="ams-etb-settings-group"><h4>Layout</h4>';
            html += this.field('number', 'maxWidth', 'Width (px)', s.maxWidth || '600');
            html += this.field('text', 'preheader', 'Preheader', s.preheader || '');
            html += '</div>';
            return html;
        },

        renderBlockSettings: function (block) {
            var p = block.props || {};
            var label = BLOCK_DEFS[block.type] ? BLOCK_DEFS[block.type].label : block.type;
            var html = '<div class="ams-etb-settings-group"><h4>' + label + ' Settings</h4>';
            switch (block.type) {
                case 'text':
                    html += this.field('textarea', 'content', 'Content (HTML)', p.content || '');
                    html += this.field('text', 'padding', 'Padding', p.padding || '10px 20px');
                    break;
                case 'hero-image':
                    html += '<p class="description" style="margin:0 0 10px;color:#666;background:#f0f6fc;padding:8px;border-radius:4px;border:1px solid #c3d9f0;"><span class="dashicons dashicons-info" style="font-size:14px;width:14px;height:14px;margin-right:4px;color:#2271b1;"></span>Hero image and text are set per campaign in the <strong>Content</strong> tab. You can set defaults here.</p>';
                    html += '<div class="ams-etb-field"><label>Default Image</label><button class="button ams-etb-pick-image" data-prop="src">Choose Default Image</button>';
                    if (p.src) html += '<br><img src="' + this.esc(p.src) + '" style="max-width:100%;margin-top:8px;border-radius:4px;" />';
                    html += '</div>';
                    html += this.field('text', 'alt', 'Alt Text', p.alt || '');
                    html += this.field('text', 'height', 'Min Height', p.height || '300px');
                    html += this.field('text', 'overlayText', 'Default Headline', p.overlayText || '');
                    html += this.field('text', 'overlaySubtext', 'Default Subtext', p.overlaySubtext || '');
                    html += this.field('text', 'textColor', 'Text Color', p.textColor || '#ffffff');
                    html += this.field('text', 'buttonText', 'Button Text', p.buttonText || '');
                    html += this.field('text', 'buttonUrl', 'Button URL', p.buttonUrl || '#');
                    html += this.field('text', 'buttonBg', 'Button BG', p.buttonBg || '#2271b1');
                    break;
                case 'image':
                    html += '<div class="ams-etb-field"><label>Image</label><button class="button ams-etb-pick-image" data-prop="src">Choose Image</button>';
                    if (p.src) html += '<br><img src="' + this.esc(p.src) + '" style="max-width:100%;margin-top:8px;border-radius:4px;" />';
                    html += '</div>';
                    html += this.field('text', 'alt', 'Alt Text', p.alt || '');
                    html += this.field('text', 'width', 'Width', p.width || '100%');
                    html += this.field('text', 'padding', 'Padding', p.padding || '10px 20px');
                    break;
                case 'button':
                    html += this.field('text', 'text', 'Button Text', p.text || '');
                    html += this.field('text', 'url', 'URL', p.url || '#');
                    html += this.field('text', 'bgColor', 'Background', p.bgColor || '#2271b1');
                    html += this.field('text', 'textColor', 'Text Color', p.textColor || '#fff');
                    html += this.field('text', 'borderRadius', 'Radius', p.borderRadius || '4px');
                    html += this.field('text', 'padding', 'Padding', p.padding || '12px 24px');
                    break;
                case 'divider':
                    html += this.field('text', 'color', 'Color', p.color || '#ccc');
                    html += this.field('text', 'thickness', 'Thickness', p.thickness || '1px');
                    html += this.field('text', 'padding', 'Padding', p.padding || '10px 20px');
                    break;
                case 'spacer':
                    html += this.field('text', 'height', 'Height', p.height || '20px');
                    break;
                case 'blank-row':
                    html += this.field('text', 'height', 'Height', p.height || '40px');
                    html += this.field('text', 'bgColor', 'Background', p.bgColor || '#f7f7f7');
                    break;
                case 'product-card':
                    html += '<div class="ams-etb-field"><label>Data Source</label><select class="ams-etb-input" data-prop="dataSource"><option value="token"' + ((p.dataSource || 'token') === 'token' ? ' selected' : '') + '>Dynamic (flow trigger)</option><option value="specific"' + (p.dataSource === 'specific' ? ' selected' : '') + '>Specific Product ID</option><option value="abandoned_cart"' + (p.dataSource === 'abandoned_cart' ? ' selected' : '') + '>Abandoned Cart</option><option value="recommended"' + (p.dataSource === 'recommended' ? ' selected' : '') + '>AI Recommended</option></select></div>';
                    if (p.dataSource === 'specific') html += this.field('text', 'specificProductId', 'Product ID', p.specificProductId || '');
                    html += this.field('text', 'buttonText', 'Button', p.buttonText || 'Shop Now');
                    html += this.field('text', 'buttonColor', 'Button BG', p.buttonColor || '#2271b1');
                    html += this.field('text', 'buttonTextColor', 'Button Text', p.buttonTextColor || '#ffffff');
                    html += this.field('text', 'padding', 'Padding', p.padding || '10px 20px');
                    break;
                case 'reviews':
                    html += '<div class="ams-etb-field"><label>Mode</label><select class="ams-etb-input" data-prop="mode"><option value="review_request"' + ((p.mode || 'review_request') === 'review_request' ? ' selected' : '') + '>Review Request CTA</option><option value="social_proof"' + (p.mode === 'social_proof' ? ' selected' : '') + '>Social Proof Cards</option><option value="review_gate"' + (p.mode === 'review_gate' ? ' selected' : '') + '>Star Rating Gate</option></select></div>';
                    html += this.field('text', 'heading', 'Heading', p.heading || '');
                    if ((p.mode || 'review_request') === 'review_request') {
                        html += this.field('text', 'buttonText', 'Button', p.buttonText || 'Leave a Review');
                        html += this.field('text', 'buttonColor', 'Button Color', p.buttonColor || '#2271b1');
                    }
                    if (p.mode === 'social_proof') {
                        html += '<div class="ams-etb-field"><label>Selection</label><select class="ams-etb-input" data-prop="selectionMode"><option value="auto_contextual"' + ((p.selectionMode || 'auto_contextual') === 'auto_contextual' ? ' selected' : '') + '>Auto (contextual)</option><option value="specific_product"' + (p.selectionMode === 'specific_product' ? ' selected' : '') + '>Specific Product</option><option value="top_rated"' + (p.selectionMode === 'top_rated' ? ' selected' : '') + '>Top Rated</option><option value="most_recent"' + (p.selectionMode === 'most_recent' ? ' selected' : '') + '>Most Recent</option></select></div>';
                        if (p.selectionMode === 'specific_product') html += this.field('text', 'productId', 'Product ID', p.productId || '');
                        html += this.field('number', 'reviewCount', 'How Many', p.reviewCount || 3);
                        html += '<div class="ams-etb-field"><label>Min Stars</label><select class="ams-etb-input" data-prop="minRating"><option value="3"' + (String(p.minRating) === '3' ? ' selected' : '') + '>3+</option><option value="4"' + (String(p.minRating || 4) === '4' ? ' selected' : '') + '>4+</option><option value="5"' + (String(p.minRating) === '5' ? ' selected' : '') + '>5 only</option></select></div>';
                        html += this.field('text', 'starColor', 'Star Color', p.starColor || '#f5a623');
                        html += this.field('text', 'cardBg', 'Card BG', p.cardBg || '#ffffff');
                    }
                    if (p.mode === 'review_gate') {
                        html += this.field('text', 'starColor', 'Star Color', p.starColor || '#f5a623');
                    }
                    html += this.field('text', 'padding', 'Padding', p.padding || '10px 20px');
                    break;
                case 'social-links':
                    html += this.field('text', 'facebook', 'Facebook', p.facebook || '');
                    html += this.field('text', 'instagram', 'Instagram', p.instagram || '');
                    html += this.field('text', 'twitter', 'X/Twitter', p.twitter || '');
                    html += this.field('text', 'youtube', 'YouTube', p.youtube || '');
                    break;
                case 'unsubscribe-footer':
                    html += this.field('textarea', 'text', 'Footer Text', p.text || '');
                    html += this.field('text', 'linkText', 'Link Text', p.linkText || 'Unsubscribe');
                    break;
                case 'greeting':
                    html += this.field('text', 'greeting', 'Greeting Word', p.greeting || 'Hi');
                    html += this.field('text', 'fallback', 'Fallback', p.fallback || 'there');
                    html += this.field('text', 'padding', 'Padding', p.padding || '10px 20px');
                    break;
                case 'order-summary':
                    html += this.field('text', 'padding', 'Padding', p.padding || '10px 20px');
                    html += '<p class="description">Shows: {{order_number}}, {{order_date}}, {{order_total}}, {{order_status}}</p>';
                    break;
                case 'cart-items':
                    html += '<p class="description" style="margin:0 0 8px;color:#666;background:#fff8e5;padding:8px;border-radius:4px;border:1px solid #f0d58c;">Best used in <strong>Abandoned Cart</strong> flows.</p>';
                    html += this.field('text', 'heading', 'Heading', p.heading || 'Items in Your Cart');
                    html += this.field('text', 'buttonText', 'Button', p.buttonText || 'Complete Order');
                    html += this.field('text', 'buttonColor', 'Button BG', p.buttonColor || '#2271b1');
                    html += this.field('text', 'buttonTextColor', 'Button Text', p.buttonTextColor || '#ffffff');
                    html += this.field('text', 'padding', 'Padding', p.padding || '10px 20px');
                    break;
                case 'coupon':
                    html += this.field('text', 'heading', 'Heading', p.heading || 'Your Exclusive Discount');
                    html += this.field('text', 'codeVar', 'Code Token', p.codeVar || '{{coupon_code}}');
                    html += this.field('text', 'bgColor', 'Background', p.bgColor || '#f0f9ff');
                    html += this.field('text', 'borderColor', 'Border', p.borderColor || '#2271b1');
                    html += this.field('text', 'fontSize', 'Code Size', p.fontSize || '22px');
                    html += this.field('text', 'padding', 'Padding', p.padding || '10px 20px');
                    break;
                case 'ai-recommendations':
                    html += this.field('text', 'heading', 'Heading', p.heading || 'Recommended For You');
                    html += this.field('text', 'padding', 'Padding', p.padding || '10px 20px');
                    break;
                case 'token-block':
                    html += '<div class="ams-etb-field"><label>Token</label><select class="ams-etb-input" data-prop="token">';
                    var tkOpts = { first_name:'First Name', last_name:'Last Name', full_name:'Full Name', email:'Email', phone:'Phone', shop_name:'Shop Name', shop_url:'Shop URL', order_number:'Order Number', order_total:'Order Total', order_date:'Order Date', order_status:'Order Status', cart_url:'Cart URL', cart_total:'Cart Total', product_name:'Product Name', product_url:'Product URL', product_price:'Product Price', coupon_code:'Coupon Code', review_link:'Review Link', unsubscribe_url:'Unsubscribe URL' };
                    for (var tk in tkOpts) { html += '<option value="' + tk + '"' + (tk === (p.token || 'first_name') ? ' selected' : '') + '>' + tkOpts[tk] + '</option>'; }
                    html += '</select></div>';
                    html += this.field('text', 'before', 'Text Before', p.before || '');
                    html += this.field('text', 'after', 'Text After', p.after || '');
                    html += this.field('text', 'textColor', 'Text Color', p.textColor || '');
                    html += '<div class="ams-etb-field"><label>Font</label><select class="ams-etb-input" data-prop="fontFamily"><option value="montserrat"' + ((p.fontFamily || 'montserrat') === 'montserrat' ? ' selected' : '') + '>Montserrat</option><option value="arial"' + (p.fontFamily === 'arial' ? ' selected' : '') + '>Arial</option><option value="georgia"' + (p.fontFamily === 'georgia' ? ' selected' : '') + '>Georgia</option><option value="verdana"' + (p.fontFamily === 'verdana' ? ' selected' : '') + '>Verdana</option><option value="courier"' + (p.fontFamily === 'courier' ? ' selected' : '') + '>Courier</option></select></div>';
                    html += this.field('text', 'fontSize', 'Font Size', p.fontSize || '16px');
                    html += this.field('text', 'padding', 'Padding', p.padding || '10px 20px');
                    break;
                case 'product-showcase':
                    html += '<p class="description" style="margin:0 0 10px;color:#666;background:#f0f6fc;padding:8px;border-radius:4px;border:1px solid #c3d9f0;"><span class="dashicons dashicons-info" style="font-size:14px;width:14px;height:14px;margin-right:4px;color:#2271b1;"></span>Product IDs are set per campaign in the <strong>Content</strong> tab. You can set default IDs here for preview.</p>';
                    html += this.field('text', 'productIds', 'Default Product IDs', p.productIds || '');
                    html += '<p class="description" style="font-size:11px;color:#999;margin:-6px 0 10px;">Comma-separated, e.g. 345, 674, 37</p>';
                    html += this.field('text', 'buttonText', 'Button Text', p.buttonText || 'SHOP NOW');
                    html += this.field('text', 'buttonBg', 'Button BG', p.buttonBg || '#000000');
                    html += this.field('text', 'buttonTextColor', 'Button Text Color', p.buttonTextColor || '#ffffff');
                    html += this.field('text', 'cardBg', 'Card BG', p.cardBg || '#f5f5f5');
                    html += this.field('select', 'showDescription', 'Show Description', p.showDescription !== false ? 'true' : 'false', { 'true': 'Yes', 'false': 'No' });
                    html += this.field('text', 'padding', 'Padding', p.padding || '10px 0');
                    break;
                default: html += '<p>No settings.</p>';
            }
            html += '</div>';
            return html;
        },

        field: function (type, name, label, value) {
            var html = '<div class="ams-etb-field"><label>' + this.esc(label) + '</label>';
            if (type === 'textarea') {
                html += '<textarea class="ams-etb-input" data-prop="' + name + '" rows="5">' + this.esc(value || '') + '</textarea>';
            } else {
                html += '<input type="' + type + '" class="ams-etb-input" data-prop="' + name + '" value="' + this.esc(value || '') + '" />';
            }
            html += '</div>';
            return html;
        },

        esc: function (s) { return s ? String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;') : ''; },

        bindEvents: function () {
            var self = this;

            this.el.on('click', '.ams-etb-tab', function () {
                self.el.find('.ams-etb-tab').removeClass('active');
                $(this).addClass('active');
                self.el.find('.ams-etb-panel').removeClass('active');
                self.el.find('.ams-etb-panel[data-panel="' + $(this).data('panel') + '"]').addClass('active');
            });

            this.el.on('dragstart', '.ams-etb-block-item', function (e) {
                e.originalEvent.dataTransfer.setData('block-type', $(this).data('type'));
                e.originalEvent.dataTransfer.effectAllowed = 'copy';
                $(this).addClass('dragging');
                self._dragging = true;
            });
            this.el.on('dragend', '.ams-etb-block-item', function () {
                $(this).removeClass('dragging');
                setTimeout(function () { self._dragging = false; }, 50);
            });

            this.el.on('dragover', '.ams-etb-drop-zone, .ams-etb-row', function (e) { e.preventDefault(); $(this).addClass('drag-over'); });
            this.el.on('dragleave', '.ams-etb-drop-zone, .ams-etb-row', function () { $(this).removeClass('drag-over'); });
            this.el.on('drop', '.ams-etb-drop-zone, .ams-etb-row', function (e) {
                e.preventDefault(); e.stopPropagation(); $(this).removeClass('drag-over');
                var type = e.originalEvent.dataTransfer.getData('block-type');
                if (!type) return;
                var defaults = BLOCK_DEFS[type] ? $.extend(true, {}, BLOCK_DEFS[type].defaults) : {};
                var rowIndex = $(this).data('index');
                if (typeof rowIndex !== 'undefined') {
                    self.structure.rows.splice(rowIndex + 1, 0, { blocks: [{ type: type, props: defaults }] });
                } else {
                    self.structure.rows.push({ blocks: [{ type: type, props: defaults }] });
                }
                self.refreshCanvas();
                var newIdx = (typeof rowIndex !== 'undefined') ? rowIndex + 1 : self.structure.rows.length - 1;
                self.selectBlock(newIdx, 0);
            });

            this.el.on('click', '.ams-etb-block-item', function () {
                if (self._dragging) return;
                var type = $(this).data('type');
                var defaults = BLOCK_DEFS[type] ? $.extend(true, {}, BLOCK_DEFS[type].defaults) : {};
                self.structure.rows.push({ blocks: [{ type: type, props: defaults }] });
                self.refreshCanvas();
                self.selectBlock(self.structure.rows.length - 1, 0);
            });

            this.el.on('click', '.ams-etb-row-action.delete', function (e) {
                e.stopPropagation();
                self.structure.rows.splice($(this).closest('.ams-etb-row').data('index'), 1);
                self.selectedRow = null;
                self.refreshCanvas();
            });
            this.el.on('click', '.ams-etb-row-action.duplicate', function (e) {
                e.stopPropagation();
                var idx = $(this).closest('.ams-etb-row').data('index');
                self.structure.rows.splice(idx + 1, 0, JSON.parse(JSON.stringify(self.structure.rows[idx])));
                self.refreshCanvas();
            });

            this.el.on('click', '.ams-etb-block', function (e) {
                e.stopPropagation();
                self.selectBlock($(this).data('row'), $(this).data('block'));
            });
            this.el.on('click', '.ams-etb-row', function () {
                var rowIdx = $(this).data('index');
                if (self.structure.rows[rowIdx] && self.structure.rows[rowIdx].blocks.length === 1) self.selectBlock(rowIdx, 0);
            });

            this.el.on('change input', '.ams-etb-input', function () {
                var prop = $(this).data('prop'), val = $(this).val();
                var panel = $(this).closest('.ams-etb-panel').data('panel');
                if (panel === 'settings') { self.structure.settings[prop] = val; self.refreshCanvas(); }
                else if (panel === 'block-settings' && self.selectedRow !== null) {
                    self.structure.rows[self.selectedRow].blocks[0].props[prop] = val;
                    self.refreshCanvas();
                }
            });

            /* WordPress Media Library picker */
            this.el.on('click', '.ams-etb-pick-image', function (e) {
                e.preventDefault();
                var prop = $(this).data('prop');
                if (!wp || !wp.media) { alert('WordPress Media Library not available.'); return; }
                var frame = wp.media({ title: 'Select Image', multiple: false, library: { type: 'image' } });
                frame.on('select', function () {
                    var attachment = frame.state().get('selection').first().toJSON();
                    if (self.selectedRow !== null && self.structure.rows[self.selectedRow]) {
                        self.structure.rows[self.selectedRow].blocks[0].props[prop] = attachment.url;
                        self.refreshCanvas();
                        var block = self.structure.rows[self.selectedRow].blocks[0];
                        self.el.find('.ams-etb-panel[data-panel="block-settings"]').html(self.renderBlockSettings(block));
                    }
                });
                frame.open();
            });

            /* Preview with dummy content */
            this.el.on('click', '.ams-etb-preview-btn', function () {
                var previewHtml = self.generatePreviewHtml();
                var w = window.open('', 'tpl_preview', 'width=700,height=600');
                w.document.open();
                w.document.write(previewHtml);
                w.document.close();
            });

            this.el.on('click', '.ams-etb-save-btn', function () {
                var btn = $(this);
                btn.prop('disabled', true).text('Saving...');
                var name = self.el.find('.ams-tpl-name-input').val() || 'Untitled Template';

                var data = { name: name, structure_json: JSON.stringify(self.structure) };

                if (self.templateId) {
                    apiFetch({
                        path: '/ams/v1/admin/email-templates/' + self.templateId,
                        method: 'PUT', headers: { 'X-WP-Nonce': cfg.nonce }, data: data,
                    }).then(function () {
                        btn.prop('disabled', false).text('Save Template');
                        self.showNotice('Template saved!', 'success');
                    }).catch(function () { btn.prop('disabled', false).text('Save Template'); });
                } else {
                    apiFetch({
                        path: '/ams/v1/admin/email-templates',
                        method: 'POST', headers: { 'X-WP-Nonce': cfg.nonce }, data: data,
                    }).then(function (res) {
                        self.templateId = res.id;
                        btn.prop('disabled', false).text('Save Template');
                        if (window.history.replaceState) {
                            var url = new URL(window.location);
                            url.searchParams.set('view', 'editor');
                            url.searchParams.set('template_id', res.id);
                            window.history.replaceState({}, '', url);
                        }
                        self.showNotice('Template created!', 'success');
                    }).catch(function () { btn.prop('disabled', false).text('Save Template'); });
                }
            });
        },

        selectBlock: function (rowIdx, blockIdx) {
            if (!this.structure.rows[rowIdx]) return;
            this.selectedRow = rowIdx;
            this.el.find('.ams-etb-row').removeClass('selected');
            this.el.find('.ams-etb-block').removeClass('selected');
            var $row = this.el.find('.ams-etb-row[data-index="' + rowIdx + '"]');
            $row.addClass('selected');
            $row.find('.ams-etb-block[data-block="' + blockIdx + '"]').addClass('selected');
            this.el.find('.ams-etb-panel[data-panel="block-settings"]').html(this.renderBlockSettings(this.structure.rows[rowIdx].blocks[blockIdx]));
            this.el.find('.ams-etb-tab').removeClass('active');
            this.el.find('.ams-etb-tab[data-panel="block-settings"]').addClass('active');
            this.el.find('.ams-etb-panel').removeClass('active');
            this.el.find('.ams-etb-panel[data-panel="block-settings"]').addClass('active');
        },

        refreshCanvas: function () {
            var s = this.structure.settings;
            var body = this.el.find('.ams-etb-email-body');
            body.html(this.renderRows());
            body.css('background', s.contentBg || '#fff');
            this.el.find('.ams-etb-email-frame').css('max-width', (parseInt(s.maxWidth) || 600) + 'px');
            this.initSortable();
            if (this.selectedRow !== null && this.structure.rows[this.selectedRow]) {
                var $row = this.el.find('.ams-etb-row[data-index="' + this.selectedRow + '"]');
                $row.addClass('selected');
                $row.find('.ams-etb-block').first().addClass('selected');
            }
        },

        initSortable: function () {
            var self = this;
            this.el.find('.ams-etb-drop-zone.has-blocks').sortable({
                items: '.ams-etb-row', handle: '.ams-etb-row-action.move',
                placeholder: 'ams-sortable-placeholder', tolerance: 'pointer',
                update: function () {
                    var newOrder = [];
                    $(this).find('.ams-etb-row').each(function () { newOrder.push(self.structure.rows[$(this).data('index')]); });
                    self.structure.rows = newOrder;
                    self.refreshCanvas();
                }
            });
        },

        showNotice: function (msg, type) {
            var n = $('<div class="notice notice-' + type + ' is-dismissible" style="position:fixed;top:40px;right:20px;z-index:9999;padding:10px 15px;"><p>' + msg + '</p></div>');
            $('body').append(n);
            setTimeout(function () { n.fadeOut(400, function () { $(this).remove(); }); }, 3000);
        },

        /* Generate full email HTML from the template structure */
        generateFullHtml: function () {
            var s = this.structure.settings;
            var font = "'Montserrat','Century Gothic','Trebuchet MS',Arial,Helvetica,sans-serif";
            var maxW = s.maxWidth || '600', bgColor = s.bgColor || '#f4f4f4', contentBg = s.contentBg || '#ffffff';
            var textColor = s.textColor || '#333', linkColor = s.linkColor || '#2271b1';
            var body = '';
            for (var i = 0; i < this.structure.rows.length; i++) {
                var row = this.structure.rows[i];
                for (var j = 0; j < (row.blocks || []).length; j++) {
                    var b = row.blocks[j], p = b.props || {}, pad = p.padding || '10px 20px';
                    body += '<tr><td>';
                    switch (b.type) {
                        case 'text': body += '<div style="padding:' + pad + ';text-align:' + (p.align || 'left') + ';font-family:' + font + ';color:' + textColor + ';line-height:1.6;">' + (p.content || '') + '</div>'; break;
                        case 'hero-image': body += '<div style="background:#111 url(' + (p.src || '') + ') center/cover no-repeat;min-height:' + (p.height || '300px') + ';text-align:center;"><div style="padding:40px 20px;color:' + (p.textColor || '#fff') + ';font-family:' + font + ';">' + (p.overlayText ? '<h2 style="margin:0 0 8px;font-size:28px;font-weight:700;">' + p.overlayText + '</h2>' : '') + (p.overlaySubtext ? '<p style="margin:0 0 16px;font-size:16px;">' + p.overlaySubtext + '</p>' : '') + (p.buttonText ? '<a href="' + (p.buttonUrl || '#') + '" style="display:inline-block;background:' + (p.buttonBg || '#2271b1') + ';color:' + (p.buttonColor || '#fff') + ';padding:12px 28px;border-radius:4px;font-weight:600;text-decoration:none;">' + p.buttonText + '</a>' : '') + '</div></div>'; break;
                        case 'image': var im = '<img src="' + (p.src || '') + '" alt="' + (p.alt || '') + '" style="max-width:' + (p.width || '100%') + ';height:auto;display:block;margin:0 auto;" />'; body += '<div style="padding:' + pad + ';text-align:' + (p.align || 'center') + ';">' + im + '</div>'; break;
                        case 'button': body += '<div style="padding:' + (p.containerPadding || '10px 20px') + ';text-align:' + (p.align || 'center') + ';"><a href="' + (p.url || '#') + '" style="display:inline-block;background:' + (p.bgColor || '#2271b1') + ';color:' + (p.textColor || '#fff') + ';font-family:' + font + ';font-size:16px;font-weight:600;text-decoration:none;padding:' + (p.padding || '12px 24px') + ';border-radius:' + (p.borderRadius || '4px') + ';">' + (p.text || 'Click') + '</a></div>'; break;
                        case 'divider': body += '<div style="padding:' + pad + ';"><hr style="border:0;border-top:' + (p.thickness || '1px') + ' ' + (p.style || 'solid') + ' ' + (p.color || '#ccc') + ';margin:0;" /></div>'; break;
                        case 'spacer': body += '<div style="height:' + (p.height || '20px') + ';">&nbsp;</div>'; break;
                        case 'product-card': body += '<table cellpadding="0" cellspacing="0" border="0" width="100%" style="font-family:' + font + ';"><tr><td style="width:40%;padding:10px;"><img src="' + (p.imageUrl || '') + '" style="max-width:100%;height:auto;" /></td><td style="width:60%;padding:10px;vertical-align:top;"><h3 style="margin:0 0 8px;">' + (p.productName || '') + '</h3><p style="margin:0 0 12px;font-size:18px;font-weight:600;">' + (p.price || '') + '</p><a href="' + (p.productUrl || '#') + '" style="display:inline-block;background:' + (p.buttonColor || '#2271b1') + ';color:' + (p.buttonTextColor || '#fff') + ';padding:10px 20px;border-radius:4px;font-weight:600;text-decoration:none;">' + (p.buttonText || 'Shop Now') + '</a></td></tr></table>'; break;
                        case 'social-links': var sl = '<div style="text-align:center;padding:' + pad + ';">'; if (p.facebook) sl += '<a href="' + p.facebook + '" style="margin:0 8px;color:' + linkColor + ';text-decoration:none;">Facebook</a>'; if (p.instagram) sl += '<a href="' + p.instagram + '" style="margin:0 8px;color:' + linkColor + ';text-decoration:none;">Instagram</a>'; if (p.twitter) sl += '<a href="' + p.twitter + '" style="margin:0 8px;color:' + linkColor + ';text-decoration:none;">X</a>'; sl += '</div>'; body += sl; break;
                        case 'unsubscribe-footer': body += '<div style="text-align:center;padding:' + (p.padding || '20px') + ';font-size:12px;color:#999;"><p style="margin:0 0 8px;">' + (p.text || '') + '</p><a href="{{unsubscribe_url}}" style="color:' + linkColor + ';">Unsubscribe</a></div>'; break;
                        case 'greeting': body += '<div style="padding:' + pad + ';font-family:' + font + ';color:' + textColor + ';">{{if ' + (p.field || 'first_name') + '}}' + (p.greeting || 'Hi') + ' {{' + (p.field || 'first_name') + '}}{{else}}' + (p.greeting || 'Hi') + ' ' + (p.fallback || 'there') + '{{/if}}</div>'; break;
                        case 'order-summary': var os = '<div style="padding:' + pad + ';font-family:' + font + ';"><table style="width:100%;font-size:14px;">'; if (p.showOrderNumber !== false) os += '<tr><td style="padding:8px 0;border-bottom:1px solid #eee;"><strong>Order</strong></td><td style="text-align:right;padding:8px 0;border-bottom:1px solid #eee;">{{order_number}}</td></tr>'; if (p.showOrderTotal !== false) os += '<tr><td style="padding:8px 0;"><strong>Total</strong></td><td style="text-align:right;padding:8px 0;font-weight:700;">{{order_total}}</td></tr>'; os += '</table></div>'; body += os; break;
                        case 'coupon': body += '<div style="padding:' + pad + ';"><div style="border:2px dashed ' + (p.borderColor || '#2271b1') + ';background:' + (p.bgColor || '#f0f9ff') + ';border-radius:8px;padding:20px;text-align:center;">' + (p.heading ? '<p style="margin:0 0 8px;font-size:13px;color:#999;text-transform:uppercase;">' + p.heading + '</p>' : '') + '<p style="margin:0;font-size:' + (p.fontSize || '22px') + ';font-weight:700;font-family:monospace;">' + (p.codeVar || '{{coupon_code}}') + '</p></div></div>'; break;
                        case 'ai-recommendations': body += '<div style="padding:' + pad + ';"><h3 style="margin:0 0 12px;font-family:' + font + ';">' + (p.heading || 'Recommended For You') + '</h3>{{ai_product_recommendations}}</div>'; break;
                        case 'blank-row': body += '<div style="height:' + (p.height || '40px') + ';background:' + (p.bgColor || '#f7f7f7') + ';">&nbsp;</div>'; break;
                        case 'product-showcase':
                            var psJson = JSON.stringify({ ids: (p.productIds || ''), btn: p.buttonText || 'SHOP NOW', btnBg: p.buttonBg || '#000000', btnColor: p.buttonTextColor || '#ffffff', cardBg: p.cardBg || '#f5f5f5', desc: p.showDescription !== false });
                            body += '<div class="ams-product-showcase" data-products="' + this.esc(psJson) + '" style="padding:' + pad + ';">{{product_showcase}}</div>'; break;
                    }
                    body += '</td></tr>';
                }
            }
            return '<!DOCTYPE html><html><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1.0"><style>@import url("https://fonts.googleapis.com/css2?family=Montserrat:wght@300;400;500;600;700;800&display=swap");</style></head><body style="margin:0;padding:0;background:' + bgColor + ';font-family:' + font + ';"><table role="presentation" cellpadding="0" cellspacing="0" border="0" width="' + maxW + '" align="center" style="max-width:' + maxW + 'px;margin:0 auto;background:' + contentBg + ';">' + body + '</table></body></html>';
        },

        /* Generate preview HTML with dummy content replacing all tokens */
        generatePreviewHtml: function () {
            var html = this.generateFullHtml();
            var shopName = cfg.siteName || 'Apotheca';
            var shopUrl = cfg.homeUrl || 'https://example.com';
            var dummyImg = 'https://placehold.co/400x400/e8e8e8/999?text=Product';

            var tokens = {
                '{{first_name}}': 'Sarah', '{{last_name}}': 'Johnson', '{{full_name}}': 'Sarah Johnson',
                '{{email}}': 'sarah@example.com', '{{phone}}': '+61 412 345 678',
                '{{shop_name}}': shopName, '{{shop_url}}': shopUrl, '{{unsubscribe_url}}': '#',
                '{{order_number}}': '#1234', '{{order_total}}': '$99.95',
                '{{order_date}}': 'March 22, 2026', '{{order_status}}': 'Completed',
                '{{cart_url}}': shopUrl + '/cart', '{{cart_total}}': '$74.50',
                '{{product_name}}': 'Hydrating Face Serum', '{{product_url}}': shopUrl + '/product/serum',
                '{{product_image_url}}': dummyImg, '{{product_price}}': '$45.00',
                '{{coupon_code}}': 'SAVE20', '{{review_link}}': '#reviews',
                '{{ai_product_recommendations}}': '<div style="text-align:center;padding:10px;color:#999;">AI product recommendations</div>'
            };

            /* Replace conditionals — always use true branch in preview */
            html = html.replace(/\{\{if\s+(\w+)\}\}([\s\S]*?)(?:\{\{else\}\}[\s\S]*?)?\{\{\/if\}\}/g, '$2');

            for (var t in tokens) { html = html.split(t).join(tokens[t]); }
            html = html.replace(/\{\{(\w+)\}\}/g, '<span style="background:#fff3cd;padding:1px 4px;border-radius:2px;font-size:12px;">$1</span>');
            return html;
        }
    };

    /* ── Templates List (React) ── */
    function TemplatesList() {
        var _s = useState([]), templates = _s[0], setTemplates = _s[1];
        var _l = useState(true), loading = _l[0], setLoading = _l[1];

        function load() {
            setLoading(true);
            apiFetch({ path: '/ams/v1/admin/email-templates', headers: { 'X-WP-Nonce': cfg.nonce } })
                .then(function (d) { setTemplates(d); setLoading(false); })
                .catch(function () { setLoading(false); });
        }
        useEffect(load, []);

        function del(id) {
            if (!confirm('Delete this template?')) return;
            apiFetch({ path: '/ams/v1/admin/email-templates/' + id, method: 'DELETE', headers: { 'X-WP-Nonce': cfg.nonce } }).then(load);
        }

        if (loading) return el(Spinner);
        if (!templates.length) return el('p', {}, 'No email templates yet. Click "Create Template" to get started.');

        return el('table', { className: 'widefat striped' },
            el('thead', {}, el('tr', {}, el('th', {}, 'Name'), el('th', {}, 'Description'), el('th', {}, 'Last Updated'), el('th', {}, 'Actions'))),
            el('tbody', {}, templates.map(function (t) {
                return el('tr', { key: t.id },
                    el('td', {}, el('a', { href: cfg.listUrl + '&view=editor&template_id=' + t.id, style: { fontWeight: 600 } }, t.name || '(Untitled)')),
                    el('td', {}, t.description || '\u2014'),
                    el('td', {}, t.updated_at || '\u2014'),
                    el('td', {}, el(Button, { isDestructive: true, isSmall: true, variant: 'secondary', onClick: function () { del(t.id); } }, 'Delete'))
                );
            }))
        );
    }

    /* ── Mount ── */
    $(document).ready(function () {
        var listNode = document.getElementById('ams-email-templates-list');
        if (listNode) wp.element.render(el(TemplatesList), listNode);

        var editorNode = document.getElementById('ams-email-template-editor');
        if (editorNode) Editor.init(editorNode);
    });

})(jQuery);
